import pytest

def test_privacy_officer_forbidden_from_cross_org_audit_events(
    api_session,
    officer_token_org_a,
    org_b_id,  # <fixture> str constant for ORG_B identifier
):
    headers = {"Authorization": f"Bearer {officer_token_org_a}"}
    resp = api_session.get(
        "/AuditEvent",
        params={"organization": org_b_id},
        headers=headers,
    )
    assert resp.status_code == 403, (
        f"Expected 403 for cross-org access, got {resp.status_code}"
    )
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome", (
        "Expected OperationOutcome in 403 response body"
    )
    severities = [
        issue["severity"]
        for issue in body.get("issue", [])
    ]
    assert "error" in severities or "fatal" in severities
